     1→/**
     2→ * InfiniteCanvas - Professional-grade pan/zoom canvas
     3→ *
     4→ * Features:
     5→ * - Pan with mouse drag (bounded to world limits)
     6→ * - Zoom with scroll wheel (centers on cursor position)
     7→ * - Initial view shows top-left of data (X=0, Y=0)
     8→ * - Sidebar sync via onViewportChange callback
     9→ *
    10→ * Coordinate System:
    11→ * - X: 0 = first day, positive = future (right)
    12→ * - Y: 0 = first train (TRAIN-001), negative = more trains (down)
    13→ *
    14→ * References:
    15→ * - D3.js zoom: https://d3js.org/d3-zoom
    16→ * - Three.js OrthographicCamera: https://threejs.org/docs/api/en/cameras/OrthographicCamera.html
    17→ * - pixi-viewport: https://github.com/pixijs-userland/pixi-viewport
    18→ */
    19→
    20→import { Canvas, useThree } from '@react-three/fiber';
    21→import { useCallback, useMemo, useEffect, useRef } from 'react';
    22→import { MesoLayer } from './layers/MesoLayer';
    23→import { MacroLayer } from './layers/MacroLayer';
    24→import { MicroLayer } from './layers/MicroLayer';
    25→import { PerfMonitor } from '../components/PerfMonitor';
    26→import type { PerfEvent } from '../components/PerfMonitor';
    27→import { getRenderData } from '../data/generator';
    28→import type { LODLevel, WorldBounds } from '../data/types';
    29→import { DEFAULT_VIEW_CONFIG, calculateWorldBounds } from '../data/types';
    30→import { useCanvasSelector, canvasActions, canvasStore } from '../state';
    31→
    32→// ─────────────────────────────────────────────────────────────
    33→// EXPORTED TYPES
    34→// ─────────────────────────────────────────────────────────────
    35→
    36→/**
    37→ * Viewport information passed to parent component
    38→ */
    39→export interface ViewportInfo {
    40→  /** Y coordinate of the TOP of the viewport in world space */
    41→  topY: number;
    42→  /** Left edge of the viewport in world X coordinates */
    43→  leftX: number;
    44→  /** Right edge of the viewport in world X coordinates */
    45→  rightX: number;
    46→}
    47→
    48→/**
    49→ * Viewport bounds in world coordinates
    50→ * Used for frustum culling - only render tasks within these bounds
    51→ */
    52→export interface ViewportBounds {
    53→  minX: number;
    54→  maxX: number;
    55→  minY: number;
    56→  maxY: number;
    57→}
    58→
    59→// ─────────────────────────────────────────────────────────────
    60→// LOD CONFIGURATION
    61→// ─────────────────────────────────────────────────────────────
    62→
    63→/**
    64→ * LOD Transition Configuration
    65→ *
    66→ * Defines blend zones around LOD thresholds for smooth transitions.
    67→ * During blend zones, both adjacent layers render with interpolated opacity.
    68→ */
    69→const LOD_THRESHOLDS = {
    70→  macroToMeso: 0.5,  // Below 0.5 = MACRO
    71→  mesoToMicro: 2.0,  // Above 2.0 = MICRO
    72→};
    73→
    74→// Size of blend zone around each threshold (±this value)
    75→const BLEND_ZONE_SIZE = 0.15;
    76→
    77→/**
    78→ * Calculate layer opacities for smooth LOD transitions
    79→ *
    80→ * Returns opacity values for each layer (0-1).
    81→ * During blend zones, adjacent layers overlap with interpolated opacity.
    82→ */
    83→function calculateLayerOpacities(zoom: number): {
    84→  macro: number;
    85→  meso: number;
    86→  micro: number;
    87→} {
    88→  const { macroToMeso, mesoToMicro } = LOD_THRESHOLDS;
    89→
    90→  // Define blend zone boundaries
    91→  const macroEnd = macroToMeso - BLEND_ZONE_SIZE; // 0.35
    92→  const mesoStart = macroToMeso + BLEND_ZONE_SIZE; // 0.65
    93→  const mesoEnd = mesoToMicro - BLEND_ZONE_SIZE; // 1.85
    94→  const microStart = mesoToMicro + BLEND_ZONE_SIZE; // 2.15
    95→
    96→  let macro = 0;
    97→  let meso = 0;
    98→  let micro = 0;
    99→
   100→  // Calculate MACRO opacity
   101→  if (zoom <= macroEnd) {
   102→    macro = 1;
   103→  } else if (zoom < mesoStart) {
   104→    // Blend zone MACRO → MESO
   105→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   106→    macro = 1 - t;
   107→  }
   108→
   109→  // Calculate MESO opacity
   110→  if (zoom < macroEnd) {
   111→    meso = 0;
   112→  } else if (zoom < mesoStart) {
   113→    // Blend zone MACRO → MESO
   114→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   115→    meso = t;
   116→  } else if (zoom <= mesoEnd) {
   117→    meso = 1;
   118→  } else if (zoom < microStart) {
   119→    // Blend zone MESO → MICRO
   120→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   121→    meso = 1 - t;
   122→  }
   123→
   124→  // Calculate MICRO opacity
   125→  if (zoom <= mesoEnd) {
   126→    micro = 0;
   127→  } else if (zoom < microStart) {
   128→    // Blend zone MESO → MICRO
   129→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   130→    micro = t;
   131→  } else {
   132→    micro = 1;
   133→  }
   134→
   135→  return { macro, meso, micro };
   136→}
   137→
   138→/**
   139→ * LODLayers - Orchestrates layer rendering with smooth transitions
   140→ *
   141→ * Renders multiple layers simultaneously during blend zones,
   142→ * with opacity interpolation for smooth visual transitions.
   143→ */
   144→function LODLayers({
   145→  tasks,
   146→  trainCount,
   147→  zoom,
   148→  viewportBounds,
   149→  hoveredTaskId,
   150→  selectedTaskId,
   151→}: {
   152→  tasks: ReturnType<typeof getRenderData>['tasks'];
   153→  trainCount: number;
   154→  zoom: number;
   155→  viewportBounds: ViewportBounds;
   156→  hoveredTaskId: string | null;
   157→  selectedTaskId: string | null;
   158→}) {
   159→  const opacities = useMemo(() => calculateLayerOpacities(zoom), [zoom]);
   160→
   161→  return (
   162→    <group>
   163→      {/* Render each layer if opacity > 0 */}
   164→      {opacities.macro > 0 && (
   165→        <MacroLayer
   166→          tasks={tasks}
   167→          trainCount={trainCount}
   168→          opacity={opacities.macro}
   169→        />
   170→      )}
   171→      {opacities.meso > 0 && (
   172→        <MesoLayer
   173→          tasks={tasks}
   174→          trainCount={trainCount}
   175→          opacity={opacities.meso}
   176→          hoveredTaskId={hoveredTaskId}
   177→          selectedTaskId={selectedTaskId}
   178→        />
   179→      )}
   180→      {opacities.micro > 0 && (
   181→        <MicroLayer
   182→          tasks={tasks}
   183→          trainCount={trainCount}
   184→          opacity={opacities.micro}
   185→          viewportBounds={viewportBounds}
   186→          hoveredTaskId={hoveredTaskId}
   187→          selectedTaskId={selectedTaskId}
   188→        />
   189→      )}
   190→    </group>
   191→  );
   192→}
   193→
   194→/**
   195→ * Navigation target for programmatic navigation
   196→ * Can specify trainIndex, dayOffset, or both
   197→ */
   198→export interface NavigationTarget {
   199→  /** Train index (0-based) to center on vertically */
   200→  trainIndex?: number;
   201→  /** Day offset from start date to center on horizontally */
   202→  dayOffset?: number;
   203→  /** Optional zoom level to set (defaults to current zoom) */
   204→  zoom?: number;
   205→}
   206→
   207→interface InfiniteCanvasProps {
   208→  zoom: number;
   209→  lod: LODLevel;
   210→  onZoomChange: (zoom: number) => void;
   211→  /**
   212→   * Called when viewport position changes.
   213→   * @param viewport - Object with topY, leftX, rightX coordinates
   214→   */
   215→  onViewportChange?: (viewport: ViewportInfo) => void;
   216→  /**
   217→   * Called when the effective minimum zoom changes.
   218→   * Used by parent to enforce zoom limits on buttons.
   219→   */
   220→  onMinZoomChange?: (minZoom: number) => void;
   221→  /**
   222→   * Request a smooth animated zoom to target level.
   223→   * Called by parent buttons for +/- zoom with animation.
   224→   */
   225→  animatedZoomTarget?: number | null;
   226→  /**
   227→   * Called when animated zoom completes or is acknowledged.
   228→   */
   229→  onAnimatedZoomComplete?: () => void;
   230→  /**
   231→   * Request navigation to a specific train/date.
   232→   * Set to null after navigation completes.
   233→   */
   234→  navigationTarget?: NavigationTarget | null;
   235→  /**
   236→   * Called when navigation animation completes.
   237→   */
   238→  onNavigationComplete?: () => void;
   239→  /**
   240→   * Whether performance monitor panel is visible (PERF-001)
   241→   */
   242→  perfVisible?: boolean;
   243→  /**
   244→   * Current performance event type for logging context (PERF-001)
   245→   */
   246→  perfEvent?: PerfEvent;
   247→}
   248→
   249→// Navigation limits
   250→const ABSOLUTE_MIN_ZOOM = 0.05; // Absolute minimum to prevent extreme zoom out
   251→const MAX_ZOOM = 5.0;
   252→
   253→// Momentum physics constants
   254→const MOMENTUM_FRICTION = 0.93; // Per-frame velocity multiplier (0.93-0.95 recommended)
   255→const MOMENTUM_MIN_VELOCITY = 0.5; // Stop threshold in world units
   256→const MOMENTUM_VELOCITY_SAMPLES = 5; // Number of velocity samples to average
   257→
   258→// Smooth zoom constants
   259→const ZOOM_ANIMATION_DURATION = 250; // ms for animated zoom transitions
   260→const ZOOM_ACCUMULATION_TIMEOUT = 50; // ms to accumulate wheel events (trackpad smoothing)
   261→const PINCH_ZOOM_SENSITIVITY = 0.01; // Sensitivity for pinch-to-zoom
   262→
   263→// Cross-platform scroll normalization constants (F121)
   264→// Based on Facebook's normalizeWheel pattern and UX_RESEARCH.md
   265→const LINE_HEIGHT = 40; // Pixels per line (for deltaMode === 1)
   266→const PAGE_HEIGHT = 800; // Pixels per page (for deltaMode === 2)
   267→const MOUSE_ZOOM_SENSITIVITY = 0.003; // Base zoom sensitivity for mouse wheel
   268→const TRACKPAD_ZOOM_SENSITIVITY = 0.001; // Lower sensitivity for trackpad (many small events)
   269→const MAX_ZOOM_DELTA_PER_EVENT = 0.5; // Cap zoom change per event to prevent jumps
   270→const TRACKPAD_DETECTION_THRESHOLD = 20; // ms - events faster than this are trackpad
   271→const TRACKPAD_EVENT_COUNT_THRESHOLD = 3; // Number of rapid events to confirm trackpad
   272→
   273→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
   274→
   275→/**
   276→ * Velocity sample for momentum calculation
   277→ * (Local type - only used for velocity tracking refs, not persisted state)
   278→ */
   279→interface VelocitySample {
   280→  x: number;
   281→  y: number;
   282→  time: number;
   283→}
   284→
   285→/**
   286→ * Local momentum animation state (includes animationId which is not in store)
   287→ * The actual momentum velocity is managed in canvasStore.viewport.momentum
   288→ */
   289→interface LocalMomentumState {
   290→  animationId: number | null;
   291→}
   292→
   293→/**
   294→ * Local zoom animation state (includes animationId)
   295→ * Animation parameters are stored in canvasStore.viewport.animation
   296→ */
   297→interface LocalZoomAnimationState {
   298→  animationId: number | null;
   299→}
   300→
   301→/**
   302→ * Pinch-to-zoom state for touch gestures
   303→ */
   304→interface PinchState {
   305→  active: boolean;
   306→  initialDistance: number;
   307→  initialZoom: number;
   308→  centerX: number;
   309→  centerY: number;
   310→  pointers: Map<number, { x: number; y: number }>;
   311→}
   312→
   313→/**
   314→ * Easing functions for smooth animations
   315→ * quadOut provides Google Maps-style smooth deceleration
   316→ */
   317→const Easing = {
   318→  quadOut: (t: number) => t * (2 - t),
   319→  cubicOut: (t: number) => 1 - Math.pow(1 - t, 3),
   320→};
   321→
   322→// Task block dimensions for hit testing (matching MesoLayer)
   323→const TASK_HEIGHT = pxPerTrain - 4;
   324→
   325→/**
   326→ * Find task at screen position (hit testing for hover/click)
   327→ *
   328→ * Converts screen coordinates to world coordinates and finds
   329→ * which task (if any) is under the cursor.
   330→ *
   331→ * @param screenX - Screen X coordinate (e.g., clientX)
   332→ * @param screenY - Screen Y coordinate (e.g., clientY)
   333→ * @param containerRect - Container element bounding rect
   334→ * @param cameraX - Camera X position in world coordinates
   335→ * @param cameraY - Camera Y position in world coordinates
   336→ * @param zoom - Current zoom level
   337→ * @param canvasWidth - Canvas width in pixels
   338→ * @param canvasHeight - Canvas height in pixels
   339→ * @param tasks - Array of tasks to test against
   340→ * @returns Task ID if found, null otherwise
   341→ */
   342→function findTaskAtPosition(
   343→  screenX: number,
   344→  screenY: number,
   345→  containerRect: DOMRect,
   346→  cameraX: number,
   347→  cameraY: number,
   348→  zoom: number,
   349→  canvasWidth: number,
   350→  canvasHeight: number,
   351→  tasks: ReturnType<typeof getRenderData>['tasks']
   352→): string | null {
   353→  // Convert screen coords to canvas coords (relative to container)
   354→  const canvasX = screenX - containerRect.left;
   355→  const canvasY = screenY - containerRect.top;
   356→
   357→  // Calculate half viewport in world units
   358→  const halfViewX = canvasWidth / 2 / zoom;
   359→  const halfViewY = canvasHeight / 2 / zoom;
   360→
   361→  // Convert canvas coords to world coords
   362→  // canvasX=0 is left edge of viewport, which is cameraX - halfViewX in world
   363→  // canvasY=0 is top edge of viewport, which is cameraY + halfViewY in world
   364→  const worldX = cameraX - halfViewX + (canvasX / zoom);
   365→  const worldY = cameraY + halfViewY - (canvasY / zoom);
   366→
   367→  // Find task at world position
   368→  for (const task of tasks) {
   369→    const taskStartX = task.startDay * pxPerDay;
   370→    const taskEndX = taskStartX + task.duration * pxPerDay;
   371→    const taskCenterY = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   372→    const taskTopY = taskCenterY + TASK_HEIGHT / 2;
   373→    const taskBottomY = taskCenterY - TASK_HEIGHT / 2;
   374→
   375→    if (
   376→      worldX >= taskStartX &&
   377→      worldX <= taskEndX &&
   378→      worldY <= taskTopY &&
   379→      worldY >= taskBottomY
   380→    ) {
   381→      return task.id;
   382→    }
   383→  }
   384→
   385→  return null;
   386→}
   387→
   388→/**
   389→ * Camera controller component (inside R3F context)
   390→ * Handles initial positioning and syncs camera with external state
   391→ *
   392→ * IMPORTANT: Uses R3F's `size` from useThree() which is the actual canvas size,
   393→ * not the container div size (which can differ due to flexbox/layout).
   394→ */
   395→function CameraController({
   396→  cameraX,
   397→  cameraY,
   398→  zoom,
   399→  worldBounds,
   400→  isInitialized,
   401→  onInitialized,
   402→  onViewportChange,
   403→}: {
   404→  cameraX: number;
   405→  cameraY: number;
   406→  zoom: number;
   407→  worldBounds: WorldBounds;
   408→  isInitialized: boolean;
   409→  onInitialized: (pos: { x: number; y: number }, size: { width: number; height: number }) => void;
   410→  onViewportChange?: (viewport: ViewportInfo) => void;
   411→}) {
   412→  const { camera, size } = useThree();
   413→
   414→  // Initialize camera position on first render using actual R3F size
   415→  useEffect(() => {
   416→    if (isInitialized || size.width === 0 || size.height === 0) return;
   417→
   418→    const halfViewX = size.width / 2 / zoom;
   419→    const halfViewY = size.height / 2 / zoom;
   420→
   421→    // Position camera to show top-left corner (X=0, Y=0)
   422→    const initialCameraX = halfViewX;
   423→    const initialCameraY = -halfViewY;
   424→
   425→    // Clamp to world bounds
   426→    const minCameraX = worldBounds.minX + halfViewX;
   427→    const maxCameraX = worldBounds.maxX - halfViewX;
   428→    const minCameraY = worldBounds.minY + halfViewY;
   429→    const maxCameraY = worldBounds.maxY - halfViewY;
   430→
   431→    const clampedX = Math.max(minCameraX, Math.min(maxCameraX, initialCameraX));
   432→    const clampedY = Math.max(minCameraY, Math.min(maxCameraY, initialCameraY));
   433→
   434→    // Update camera
   435→    camera.position.x = clampedX;
   436→    camera.position.y = clampedY;
   437→    (camera as any).zoom = zoom;
   438→    camera.updateProjectionMatrix();
   439→
   440→    // Notify parent of initial position and actual canvas size
   441→    onInitialized({ x: clampedX, y: clampedY }, { width: size.width, height: size.height });
   442→
   443→    // Notify viewport change with full viewport info
   444→    const topY = clampedY + halfViewY;
   445→    const leftX = clampedX - halfViewX;
   446→    const rightX = clampedX + halfViewX;
   447→    onViewportChange?.({ topY, leftX, rightX });
   448→  }, [size, zoom, worldBounds, camera, isInitialized, onInitialized, onViewportChange]);
   449→
   450→  // Sync camera with external state changes (after initialization)
   451→  useEffect(() => {
   452→    if (!isInitialized) return;
   453→
   454→    camera.position.x = cameraX;
   455→    camera.position.y = cameraY;
   456→    (camera as any).zoom = zoom;
   457→    camera.updateProjectionMatrix();
   458→  }, [camera, cameraX, cameraY, zoom, isInitialized]);
   459→
   460→  return null;
   461→}
   462→
   463→export function InfiniteCanvas({
   464→  zoom,
   465→  lod,
   466→  onZoomChange,
   467→  onViewportChange,
   468→  onMinZoomChange,
   469→  animatedZoomTarget,
   470→  onAnimatedZoomComplete,
   471→  navigationTarget,
   472→  onNavigationComplete,
   473→  perfVisible = false,
   474→  perfEvent = 'idle',
   475→}: InfiniteCanvasProps) {
   476→  const containerRef = useRef<HTMLDivElement>(null);
   477→
   478→  // ─────────────────────────────────────────────────────────────
   479→  // STATE FROM CANVAS MACHINE (replaces useState)
   480→  // Using useSyncExternalStore under the hood - no stale closures!
   481→  // ─────────────────────────────────────────────────────────────
