  1062→    const targetZoom = Math.max(effectiveMinZoom, Math.min(MAX_ZOOM, animatedZoomTarget));
  1063→    if (Math.abs(targetZoom - zoom) < 0.001) {
  1064→      onAnimatedZoomComplete?.();
  1065→      return;
  1066→    }
  1067→
  1068→    // Zoom toward center (no cursor offset)
  1069→    const clamped = clampCameraToWorld(cameraPos.x, cameraPos.y, targetZoom);
  1070→    animateZoomTo(targetZoom, clamped.x, clamped.y, ZOOM_ANIMATION_DURATION);
  1071→
  1072→    // Acknowledge the request
  1073→    onAnimatedZoomComplete?.();
  1074→  }, [animatedZoomTarget, isInitialized, zoom, effectiveMinZoom, cameraPos, clampCameraToWorld, animateZoomTo, onAnimatedZoomComplete]);
  1075→
  1076→  // Handle navigation requests from parent (F124: sidebar/timeline navigation)
  1077→  useEffect(() => {
  1078→    if (navigationTarget == null || !isInitialized) return;
  1079→
