  1081→    stopMomentum();
  1082→    stopZoomAnimation();
  1083→
  1084→    // Calculate target camera position from trainIndex and/or dayOffset
  1085→    // trainIndex → Y position: trainIndex * pxPerTrain (negative because Y goes down)
  1086→    // dayOffset → X position: dayOffset * pxPerDay
  1087→    let targetCameraX = cameraPos.x;
  1088→    let targetCameraY = cameraPos.y;
  1089→    const targetZoom = navigationTarget.zoom != null
  1090→      ? Math.max(effectiveMinZoom, Math.min(MAX_ZOOM, navigationTarget.zoom))
  1091→      : zoom;
