  1095→      // Camera Y should be positioned so the train is in the center of viewport
  1096→      // Train position in world: -trainIndex * pxPerTrain - pxPerTrain / 2
  1097→      targetCameraY = -navigationTarget.trainIndex * pxPerTrain - pxPerTrain / 2;
  1098→    }
  1099→
  1100→    if (navigationTarget.dayOffset != null) {
  1101→      // Center on the date
  1102→      // Day position in world: dayOffset * pxPerDay
  1103→      targetCameraX = navigationTarget.dayOffset * pxPerDay;
  1104→    }
  1105→
  1106→    // Clamp to world bounds
  1107→    const clamped = clampCameraToWorld(targetCameraX, targetCameraY, targetZoom);
  1108→
  1109→    // Animate to target position
  1110→    animateZoomTo(targetZoom, clamped.x, clamped.y, 350); // 350ms for navigation
  1111→
  1112→    // Acknowledge the request
  1113→    onNavigationComplete?.();
  1114→  }, [navigationTarget, isInitialized, zoom, effectiveMinZoom, cameraPos, clampCameraToWorld, animateZoomTo, stopMomentum, stopZoomAnimation, onNavigationComplete]);
  1115→
  1116→  /**
  1117→   * Handle pan start / pinch start
  1118→   *
  1119→   * Now uses canvasStore to get camera position - no stale closures
  1120→   */
  1121→  const handlePointerDown = useCallback(
  1122→    (e: React.PointerEvent) => {
  1123→      if (!isInitialized) return;
  1124→
  1125→      const pinch = pinchRef.current;
  1126→
  1127→      // Track pointer for pinch detection
  1128→      pinch.pointers.set(e.pointerId, { x: e.clientX, y: e.clientY });
  1129→
  1130→      // Check for pinch gesture (2 pointers)
  1131→      if (pinch.pointers.size === 2) {
