  1406→      const state = canvasStore.getState();
  1407→
  1408→      const container = containerRef.current;
  1409→      if (!container) return;
  1410→
  1411→      const rect = container.getBoundingClientRect();
  1412→      const camera = state.viewport.camera;
  1413→
  1414→      // Find task at click position
  1415→      const taskId = findTaskAtPosition(
  1416→        e.clientX,
  1417→        e.clientY,
  1418→        rect,
  1419→        camera.x,
  1420→        camera.y,
  1421→        zoom,
  1422→        canvasSize.width,
  1423→        canvasSize.height,
  1424→        tasks
  1425→      );
  1426→
  1427→      if (taskId) {
  1428→        // Toggle selection: if clicking same task, deselect; otherwise, select
  1429→        if (taskId === state.interaction.selectedTaskId) {
  1430→          canvasStore.dispatch(canvasActions.interaction.clearSelection());
  1431→        } else {
  1432→          canvasStore.dispatch(canvasActions.interaction.setSelectedTask(taskId));
  1433→        }
  1434→      } else {
  1435→        // Clicked on background: clear selection
  1436→        if (state.interaction.selectedTaskId !== null) {
  1437→          canvasStore.dispatch(canvasActions.interaction.clearSelection());
  1438→        }
  1439→      }
  1440→    },
  1441→    [isInitialized, zoom, canvasSize, tasks]
  1442→  );
  1443→
  1444→  /**
  1445→   * Calculate viewport bounds for frustum culling
  1446→   * This determines which tasks are visible and need to be rendered
  1447→   */
  1448→  const viewportBounds = useMemo<ViewportBounds>(() => {
  1449→    const halfViewX = canvasSize.width / 2 / zoom;
  1450→    const halfViewY = canvasSize.height / 2 / zoom;
  1451→
  1452→    return {
  1453→      minX: cameraPos.x - halfViewX,
  1454→      maxX: cameraPos.x + halfViewX,
  1455→      minY: cameraPos.y - halfViewY,
  1456→      maxY: cameraPos.y + halfViewY,
  1457→    };
  1458→  }, [cameraPos.x, cameraPos.y, canvasSize.width, canvasSize.height, zoom]);
