/**
 * MMS Data Types
 *
 * Architecture: Persistence vs Rendering
 *
 * Data flows through two distinct layers:
 *
 * Persistent (JSON/API) → Runtime (in memory) → Rendering (canvas)
 *   startDate: string      (Date objects)       startDay: 74
 *   "2024-03-15"           for logic            trainIndex: 5
 *
 * Why this separation?
 * - Date objects cannot be serialized to JSON (become {})
 * - Canvas needs numeric offsets for position calculations
 * - Domain logic needs semantic dates for business rules
 */

// ─────────────────────────────────────────────────────────────
// ENUMS & CONSTANTS
// ─────────────────────────────────────────────────────────────

export type AssetType = 'ALSTOM' | 'KINKI';
export type TaskType = 'maintenance' | 'overhaul' | 'inspection';
export type MaintenanceLevel = 'A' | 'B' | 'C' | 'D';

// ─────────────────────────────────────────────────────────────
// DOMAIN TYPES (Persistent/Serializable)
// These types can be saved to JSON, sent via API, or stored in localStorage.
// ─────────────────────────────────────────────────────────────

export interface Train {
  id: string;              // "TRAIN-001" or "ALT-001"
  name: string;            // Display name
  assetType: AssetType;    // Fleet type
}

export interface Task {
  id: string;              // Unique identifier
  trainId: string;         // Reference to Train.id
  startDate: string;       // ISO 8601 date: "2024-03-15"
  endDate: string;         // ISO 8601 date: "2024-03-20"
  type: TaskType;          // Visual category
  hasConflict: boolean;    // Conflict indicator
}

export interface DatasetMeta {
  startDate: string;       // ISO 8601: "2024-01-01"
  trainCount: number;      // Number of trains
  years: number;           // Time range in years
}

export interface GeneratedData {
  trains: Train[];
  tasks: Task[];
  meta: DatasetMeta;
}

// ─────────────────────────────────────────────────────────────
// RENDERING TYPES (Runtime/Calculated)
// These types are computed when data loads and used by the canvas.
// Never persisted.
// ─────────────────────────────────────────────────────────────

export type TaskColor = 'blue' | 'orange' | 'gray';

export interface TaskRender {
  id: string;              // Same as Task.id
  trainIndex: number;      // Y position (0-based index in trains array)
  startDay: number;        // X position (days since meta.startDate)
  duration: number;        // Width (days)
  color: TaskColor;        // Derived from Task.type
  hasConflict: boolean;    // Passthrough from Task
  type: TaskType;          // For label display in MicroLayer
}

export const TYPE_TO_COLOR: Record<TaskType, TaskColor> = {
  maintenance: 'blue',
  overhaul: 'orange',
  inspection: 'gray',
};

// ─────────────────────────────────────────────────────────────
// WORLD BOUNDS (Navigation limits)
// ─────────────────────────────────────────────────────────────

/**
 * Defines the navigable world boundaries.
 * Camera will be clamped to these bounds.
 *
 * Coordinate system:
 * - X: 0 = first day, positive = future
 * - Y: 0 = top (TRAIN-001), negative = down (more trains)
 */
export interface WorldBounds {
  minX: number;  // 0 (first day)
  maxX: number;  // totalDays * pxPerDay
  minY: number;  // -trainCount * pxPerTrain (bottom)
  maxY: number;  // 0 (top)
}

// ─────────────────────────────────────────────────────────────
// CANVAS CONFIGURATION
// ─────────────────────────────────────────────────────────────

export interface ViewConfig {
  pxPerDay: number;        // Pixels per day (X scale)
  pxPerTrain: number;      // Pixels per train row (Y scale)
  minZoom: number;         // Minimum zoom level
  maxZoom: number;         // Maximum zoom level
  zoomSensitivity: number; // Scroll sensitivity
  lodThresholds: {
    macro: number;         // Below this → MACRO view
    micro: number;         // Above this → MICRO view
  };
}

export type LODLevel = 'MACRO' | 'MESO' | 'MICRO';

export interface ViewportState {
  zoom: number;
  panX: number;
  panY: number;
  lod: LODLevel;
}

// ─────────────────────────────────────────────────────────────
// DEFAULT VALUES
// ─────────────────────────────────────────────────────────────

export const DEFAULT_VIEW_CONFIG: ViewConfig = {
  pxPerDay: 10,
  pxPerTrain: 24,
  minZoom: 0.1,
  maxZoom: 5,
  zoomSensitivity: 0.002,
  lodThresholds: {
    macro: 0.5,
    micro: 2.0,
  },
};

export const DEFAULT_DATASET_META: DatasetMeta = {
  startDate: '2024-01-01',
  trainCount: 50,
  years: 10,
};

/**
 * Calculate world bounds from dataset metadata
 */
export function calculateWorldBounds(
  trainCount: number,
  totalDays: number,
  config: ViewConfig = DEFAULT_VIEW_CONFIG
): WorldBounds {
  return {
    minX: 0,
    maxX: totalDays * config.pxPerDay,
    minY: -trainCount * config.pxPerTrain,
    maxY: 0,
  };
}

/**
 * Data bounds with padding for visualization
 */
export interface DataBounds {
  minX: number;
  maxX: number;
  minY: number;
  maxY: number;
  width: number;
  height: number;
  centerX: number;
  centerY: number;
}

/**
 * Calculate actual data bounds from tasks (not theoretical world bounds)
 * This is used to fit the initial view to the actual data range.
 *
 * @param tasks - Array of rendered tasks with position data
 * @param trainCount - Total number of trains
 * @param config - View configuration
 * @param padding - Padding in pixels around the data bounds
 */
export function calculateDataBounds(
  tasks: TaskRender[],
  trainCount: number,
  config: ViewConfig = DEFAULT_VIEW_CONFIG,
  padding: number = 50
): DataBounds {
  if (tasks.length === 0) {
    // No tasks, return default bounds
    return {
      minX: 0,
      maxX: config.pxPerDay * 365,
      minY: -trainCount * config.pxPerTrain,
      maxY: 0,
      width: config.pxPerDay * 365,
      height: trainCount * config.pxPerTrain,
      centerX: (config.pxPerDay * 365) / 2,
      centerY: (-trainCount * config.pxPerTrain) / 2,
    };
  }

  // Find min/max from actual task positions
  let minStartDay = Infinity;
  let maxEndDay = -Infinity;
  let minTrainIndex = Infinity;
  let maxTrainIndex = -Infinity;

  for (const task of tasks) {
    minStartDay = Math.min(minStartDay, task.startDay);
    maxEndDay = Math.max(maxEndDay, task.startDay + task.duration);
    minTrainIndex = Math.min(minTrainIndex, task.trainIndex);
    maxTrainIndex = Math.max(maxTrainIndex, task.trainIndex);
  }

  // Convert to pixel coordinates
  const minX = minStartDay * config.pxPerDay - padding;
  const maxX = maxEndDay * config.pxPerDay + padding;
  // Y is negative (trains go downward)
  const maxY = -minTrainIndex * config.pxPerTrain + padding;
  const minY = -(maxTrainIndex + 1) * config.pxPerTrain - padding;

  const width = maxX - minX;
  const height = maxY - minY;

  return {
    minX,
    maxX,
    minY,
    maxY,
    width,
    height,
    centerX: minX + width / 2,
    centerY: minY + height / 2,
  };
}

/**
 * Calculate initial camera position and zoom to fit data bounds in viewport
 *
 * Follows the pattern used by D3.js fitExtent, Gantt chart zoomToFit, and pixi-viewport fitWorld
 *
 * Strategy:
 * - If data fits comfortably at reasonable zoom (0.5x - 1.5x), fit all data
 * - If data is too large (would require < 0.5x zoom), show starting portion at 0.5x zoom
 * - This provides a good initial UX while allowing users to zoom out for full overview
 *
 * @param dataBounds - The data bounds to fit
 * @param viewportWidth - Viewport width in pixels
 * @param viewportHeight - Viewport height in pixels
 * @param maxZoom - Maximum zoom level (for performance/UX)
 * @param minZoom - Minimum zoom level for initial view
 */
export function calculateFitToView(
  dataBounds: DataBounds,
  viewportWidth: number,
  viewportHeight: number,
  maxZoom: number = 1.5,
  minZoom: number = 0.5
): { cameraX: number; cameraY: number; zoom: number } {
  // Calculate zoom needed to fit all data in viewport
  const zoomX = viewportWidth / dataBounds.width;
  const zoomY = viewportHeight / dataBounds.height;
  const fitAllZoom = Math.min(zoomX, zoomY);

  // Clamp zoom to reasonable initial range
  const zoom = Math.max(minZoom, Math.min(maxZoom, fitAllZoom));

  // If we can fit all data at the calculated zoom, center on data
  if (fitAllZoom >= minZoom) {
    return {
      cameraX: dataBounds.centerX,
      cameraY: dataBounds.centerY,
      zoom,
    };
  }

  // Data is too large - show starting portion (top-left of data bounds)
  // Calculate camera position to show left edge and top of data
  const halfViewX = viewportWidth / 2 / zoom;
  const halfViewY = viewportHeight / 2 / zoom;

  return {
    cameraX: dataBounds.minX + halfViewX,
    cameraY: dataBounds.maxY - halfViewY, // maxY is the top (less negative)
    zoom,
  };
}

// ─────────────────────────────────────────────────────────────
// FUTURE EXTENSIONS (Optional Fields)
// These fields can be added without breaking existing code.
// ─────────────────────────────────────────────────────────────

// Extended Train (future)
export interface TrainExtended extends Train {
  carsCount?: number;
  currentMileageKm?: number;
  avgDailyMileageKm?: number;
  status?: 'operational' | 'maintenance' | 'out-of-service';
}

// Extended Task (future)
export interface TaskExtended extends Task {
  maintenanceLevel?: MaintenanceLevel;
  manHours?: number;
  estimatedCost?: number;
  dependencies?: string[];
  status?: 'scheduled' | 'in-progress' | 'completed';
}

// Conflict as separate entity (future)
export interface Conflict {
  id: string;
  taskIds: [string, string];
  type: 'overlap' | 'resource' | 'dependency';
  severity: 'low' | 'medium' | 'high';
  description?: string;
}

