     1→/**
     2→ * Mock Data Generator
     3→ *
     4→ * Generates test data for the MMS visualization:
     5→ * - 50 trains (30 ALSTOM + 20 KINKI)
     6→ * - 10 years of tasks per train
     7→ * - ~10-12 tasks per train per year
     8→ * - ~5% of tasks have conflict flags
     9→ */
    10→
    11→import type {
    12→  Train,
    13→  Task,
    14→  TaskRender,
    15→  GeneratedData,
    16→  DatasetMeta,
    17→  TaskType,
    18→  AssetType,
    19→} from './types';
    20→import { TYPE_TO_COLOR, DEFAULT_DATASET_META } from './types';
    21→
    22→// ─────────────────────────────────────────────────────────────
    23→// DATE HELPERS
    24→// ─────────────────────────────────────────────────────────────
    25→
    26→/**
    27→ * Format date as ISO 8601 string (YYYY-MM-DD)
    28→ */
    29→function formatISO(date: Date): string {
    30→  return date.toISOString().split('T')[0];
    31→}
    32→
    33→/**
    34→ * Add days to a date
    35→ */
    36→function addDays(date: Date | string, days: number): Date {
    37→  const d = typeof date === 'string' ? new Date(date) : new Date(date);
    38→  d.setDate(d.getDate() + days);
    39→  return d;
    40→}
    41→
    42→/**
    43→ * Calculate days between two dates
    44→ */
    45→function daysBetween(start: Date | string, end: Date | string): number {
    46→  const s = typeof start === 'string' ? new Date(start) : start;
    47→  const e = typeof end === 'string' ? new Date(end) : end;
    48→  const diffTime = e.getTime() - s.getTime();
    49→  return Math.floor(diffTime / (1000 * 60 * 60 * 24));
    50→}
    51→
    52→// ─────────────────────────────────────────────────────────────
    53→// DATA GENERATION
    54→// ─────────────────────────────────────────────────────────────
    55→
    56→/**
    57→ * Generate train entities
    58→ */
    59→function generateTrains(count: number): Train[] {
    60→  return Array.from({ length: count }, (_, i) => {
    61→    const isAlstom = i < Math.floor(count * 0.6); // 60% Alstom
    62→    return {
    63→      id: `TRAIN-${String(i + 1).padStart(3, '0')}`,
    64→      name: `Train ${i + 1}`,
    65→      assetType: (isAlstom ? 'ALSTOM' : 'KINKI') as AssetType,
    66→    };
    67→  });
    68→}
    69→
    70→/**
    71→ * Generate tasks for all trains
    72→ */
    73→function generateTasks(trains: Train[], meta: DatasetMeta): Task[] {
    74→  const tasks: Task[] = [];
    75→  const types: TaskType[] = ['maintenance', 'overhaul', 'inspection'];
    76→
    77→  trains.forEach((train, trainIndex) => {
    78→    for (let year = 0; year < meta.years; year++) {
    79→      // 8-12 tasks per year per train
    80→      const tasksPerYear = 8 + Math.floor(Math.random() * 5);
    81→
    82→      for (let t = 0; t < tasksPerYear; t++) {
    83→        // First task of year 0 for each train starts early (within first 60 days)
    84→        // This ensures data is visible at initial camera position
    85→        let dayOffset: number;
    86→        if (year === 0 && t === 0) {
    87→          dayOffset = trainIndex * 3 + Math.floor(Math.random() * 30);
    88→        } else {
    89→          dayOffset = year * 365 + Math.floor(Math.random() * 360);
    90→        }
    91→        const duration = 2 + Math.floor(Math.random() * 10);
    92→        const startDate = addDays(meta.startDate, dayOffset);
    93→        const endDate = addDays(startDate, duration);
    94→
    95→        tasks.push({
    96→          id: `${train.id}-${year}-${t}`,
    97→          trainId: train.id,
    98→          startDate: formatISO(startDate),
    99→          endDate: formatISO(endDate),
   100→          type: types[Math.floor(Math.random() * types.length)],
   101→          hasConflict: Math.random() < 0.05, // 5% conflict rate
   102→        });
   103→      }
   104→    }
   105→  });
   106→
   107→  return tasks;
   108→}
   109→
   110→/**
   111→ * Generate complete dataset
   112→ */
   113→export function generateData(meta: DatasetMeta = DEFAULT_DATASET_META): GeneratedData {
   114→  const trains = generateTrains(meta.trainCount);
   115→  const tasks = generateTasks(trains, meta);
   116→
   117→  return { trains, tasks, meta };
   118→}
   119→
   120→// ─────────────────────────────────────────────────────────────
   121→// RENDER DATA PREPARATION
   122→// ─────────────────────────────────────────────────────────────
   123→
   124→/**
   125→ * Transform persistent data to render-ready format
   126→ *
   127→ * Converts:
   128→ * - trainId → trainIndex (Y position)
   129→ * - startDate/endDate → startDay/duration (X position and width)
   130→ * - type → color
   131→ */
   132→export function prepareRenderData(data: GeneratedData): {
   133→  trains: Train[];
   134→  tasks: TaskRender[];
   135→} {
   136→  // Create train index lookup map
   137→  const trainIndexMap = new Map<string, number>(
   138→    data.trains.map((t, i) => [t.id, i])
   139→  );
   140→
   141→  // Transform tasks to render format
   142→  const tasks: TaskRender[] = data.tasks.map((task) => {
   143→    const trainIndex = trainIndexMap.get(task.trainId);
   144→    if (trainIndex === undefined) {
   145→      throw new Error(`Train not found: ${task.trainId}`);
   146→    }
   147→
   148→    const startDay = daysBetween(data.meta.startDate, task.startDate);
   149→    const duration = daysBetween(task.startDate, task.endDate);
   150→
   151→    return {
   152→      id: task.id,
   153→      trainIndex,
   154→      startDay,
   155→      duration,
   156→      color: TYPE_TO_COLOR[task.type],
   157→      hasConflict: task.hasConflict,
   158→      type: task.type,
   159→    };
   160→  });
   161→
   162→  return { trains: data.trains, tasks };
   163→}
   164→
   165→// ─────────────────────────────────────────────────────────────
   166→// PRE-GENERATED DATA (for immediate use)
   167→// ─────────────────────────────────────────────────────────────
   168→
   169→// Generate data once at module load for consistent results
   170→const _generatedData = generateData();
   171→const _renderData = prepareRenderData(_generatedData);
   172→
   173→/**
   174→ * Get pre-generated dataset (persistent format)
   175→ */
   176→export function getData(): GeneratedData {
   177→  return _generatedData;
   178→}
   179→
   180→/**
   181→ * Get pre-generated render data (canvas-ready format)
   182→ */
   183→export function getRenderData(): { trains: Train[]; tasks: TaskRender[] } {
   184→  return _renderData;
   185→}
   186→
   187→/**
   188→ * Get just the trains array
   189→ */
   190→export function getTrains(): Train[] {
   191→  return _generatedData.trains;
   192→}
   193→
   194→/**
   195→ * Get just the render tasks array
   196→ */
   197→export function getTasks(): TaskRender[] {
   198→  return _renderData.tasks;
